local UIAnim = require "widgets/uianim" local G = DYCLegendary local require = G.DYCModRequire local odwutil = require( "dyc_odwutil" ) local ShowObjectDetail = odwutil.ShowObjectDetail local ClearUpdateOdwTask = odwutil.ClearUpdateOdwTask local CreateUpdateOdwTask = odwutil.CreateUpdateOdwTask local StrSpl = G.lib.StrSpl local StringStartWith = G.lib.StringStartWith local function OnGainFocus(self, ...) local item = self.item ShowObjectDetail(item, self) ClearUpdateOdwTask(self) CreateUpdateOdwTask(self, item) return self.dycOldOnGainFocus(self, ...) end local function OnLoseFocus(self, ...) ShowObjectDetail(nil, self) ClearUpdateOdwTask(self) return self.dycOldOnLoseFocus(self, ...) end local function StartDrag(self, ...) self.dycCooldown:Hide() return self.dycOldStartDrag(self, ...) end local function Kill(self, ...) ShowObjectDetail(nil, self) return self.dycOldKill(self, ...) end local function SetCooldownPercent(self, p) p = p or 0x1 p = math.max(0x0, math.min(p, 0x1)) if not self.dycCooldown.shown then self.dycCooldown:Show() end self.dycCooldown:GetAnimState():SetPercent( "recharge" , p) if p == 0x1 then self.dycCooldown:GetAnimState():PlayAnimation( "frame_pst" ) end end local function DYCItemTile(self) local item = self.item self.dycOldOnGainFocus = self.OnGainFocus self.OnGainFocus = OnGainFocus self.dycOldOnLoseFocus = self.OnLoseFocus self.OnLoseFocus = OnLoseFocus self.dycOldKill = self.Kill self.Kill = Kill self.dycOldStartDrag = self.StartDrag self.StartDrag = StartDrag self.dycCooldown = self:AddChild(UIAnim()) self.dycCooldown:GetAnimState():SetBank( "recharge_meter" ) self.dycCooldown:GetAnimState():SetBuild( "dyc_recharge_meter" ) self.dycCooldown:Hide() self.dycCooldown:SetClickable(false) self.SetCooldownPercent = SetCooldownPercent self.inst:ListenForEvent( "cooldownchange" , function(inst, data) self:SetCooldownPercent(data.percent) end, item) end return DYCItemTile 